tmp = check_C(xr{13}, PB.lb_C_work(13), PB.ub_C_work(13), 'x13');
xh(13) = map_C_to_orig(tmp, PB.lb_C_work(13), PB.ub_C_work(13), PB.lb_orig(13), PB.ub_orig(13));
xh(14) = check_K(xr{14}, PB.K14_labels, PB.K14_embed, 'x14');
xh(15) = check_D(xr{15}, PB.D15_vals, 'x15');
tmp = check_C(xr{16}, PB.lb_C_work(16), PB.ub_C_work(16), 'x16');
xh(16) = map_C_to_orig(tmp, PB.lb_C_work(16), PB.ub_C_work(16), PB.lb_orig(16), PB.ub_orig(16));
xh(17) = check_D(xr{17}, PB.D17_vals, 'x17');
