tmp = check_C(xr{19}, PB.lb_C_work(19), PB.ub_C_work(19), 'x19');
xh(19) = map_C_to_orig(tmp, PB.lb_C_work(19), PB.ub_C_work(19), PB.lb_orig(19), PB.ub_orig(19));
xh(20) = check_K(xr{20}, PB.K20_labels, PB.K20_embed, 'x20');
