tmp = check_C(xr{22}, PB.lb_C_work(22), PB.ub_C_work(22), 'x22');
xh(22) = map_C_to_orig(tmp, PB.lb_C_work(22), PB.ub_C_work(22), PB.lb_orig(22), PB.ub_orig(22));
